import React, { useState } from "react";
import "./CoursesPage.scss";

// Импортируем типы из файлов (переименуем чтобы избежать конфликтов)
import type { Course as ImportedCourse } from "../../";
import type { Deadline as ImportedDeadline } from "../../Types/deadline";

// Interfaces (используем переименованные типы)
interface Course extends ImportedCourse {} // Наследуем от импортированного
interface Deadline extends ImportedDeadline {} // Наследуем от импортированного

interface CoursesPageProps {
  courses: ImportedCourse[];
  deadlines: ImportedDeadline[];
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onViewCourse: (courseId: string) => void;
  onAddCourse: (course: Omit<ImportedCourse, "id">) => void;
}

// ... остальной код компонентов без изменений (Sidebar, TopBar, CourseModal)

export function CoursesPage({
  courses,
  deadlines,
  onNavigate,
  onLogout,
  onViewCourse,
  onAddCourse,
}: CoursesPageProps) {
  const [showAddModal, setShowAddModal] = useState(false);

  const getUpcomingTasksCount = (courseId: string) => {
    return deadlines.filter(
      (d) => d.courseId === courseId && d.status === "upcoming"
    ).length;
  };

  return (
    <div className="courses-page">
      <Sidebar
        currentPage="courses"
        onNavigate={onNavigate}
        onLogout={onLogout}
      />

      <div className="main-content">
        <TopBar userName="Alex" />

        <main className="content">
          {/* Уменьшил отступы в header */}
          <div className="courses-header">
            <div className="courses-header__text">
              <h1 className="courses-header__title">My Courses</h1>
              <p className="courses-header__subtitle">
                Organize and track all your university courses
              </p>
            </div>
            <button
              onClick={() => setShowAddModal(true)}
              className="btn btn--add-course"
            >
              <span className="btn__icon">+</span>
              Add Course
            </button>
          </div>

          {courses.length === 0 ? (
            <div className="empty-state">
              <span className="empty-state__icon">📚</span>
              <h3 className="empty-state__title">No courses yet</h3>
              <p className="empty-state__text">
                Add your first course to get started
              </p>
              <button
                onClick={() => setShowAddModal(true)}
                className="btn btn--primary"
              >
                <span className="btn__icon">+</span>
                Add Course
              </button>
            </div>
          ) : (
            <div className="courses-grid">
              {courses.map((course) => {
                const upcomingCount = getUpcomingTasksCount(course.id);

                return (
                  <div
                    key={course.id}
                    className="course-card"
                    onClick={() => onViewCourse(course.id)}
                  >
                    <div
                      className="course-card__banner"
                      style={{ backgroundColor: course.color }}
                    >
                      <div className="course-card__overlay" />
                      <div className="course-card__icon">📚</div>
                    </div>

                    <div className="course-card__content">
                      <h3 className="course-card__title">{course.title}</h3>

                      <div className="course-card__details">
                        <div className="course-card__detail">
                          <span className="course-card__detail-icon">👤</span>
                          <span className="course-card__detail-text">
                            {course.instructor}
                          </span>
                        </div>
                        <div className="course-card__detail">
                          <span className="course-card__detail-icon">⏰</span>
                          <span className="course-card__detail-text">
                            {course.semester}
                          </span>
                        </div>
                      </div>

                      <div className="course-card__footer">
                        <span className="course-card__tasks-label">
                          Upcoming tasks
                        </span>
                        <span
                          className="course-card__tasks-count"
                          style={{
                            backgroundColor:
                              upcomingCount > 0
                                ? `${course.color}20`
                                : "#f3f4f6",
                            color: upcomingCount > 0 ? course.color : "#6b7280",
                          }}
                        >
                          {upcomingCount}
                        </span>
                      </div>

                      <button className="course-card__view-btn">
                        View Details →
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </main>
      </div>

      {showAddModal && (
        <CourseModal
          onSave={onAddCourse}
          onClose={() => setShowAddModal(false)}
        />
      )}
    </div>
  );
}
